fun main() {
    val capitals = mapOf(
        "USA" to "Washington, D.C.",
        "UK" to "London",
        "France" to "Paris"
    )

    println(capitals["France"])  // Paris
    println(capitals["Japan"] ?: "Unknown")

    // Transform
    val upper = capitals.mapKeys { it.key.uppercase() }
    println(upper)

    // Mutable
    val scores = mutableMapOf("Alice" to 10, "Bob" to 20)
    scores["Charlie"] = 30
    println(scores)
}
